import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class FileReadExample {
    public static void main(String[] args) {
        String userInput = "../secretfile.txt"; // User input with path traversal

        // Validate and sanitize user input to prevent path traversal
        String safePath = Paths.get("resources", userInput).normalize().toString();

        try {
            File file = new File(safePath);
            if (file.exists() && file.isFile()) {
                FileInputStream fis = new FileInputStream(file);

                int content;
                while ((content = fis.read()) != -1) {
                    System.out.print((char) content);
                }

                fis.close();
            } else {
                System.out.println("File not found or is a directory.");
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Path Traversal
